  objectBehavior$Dir$Code.create(f, 'ma_vv', 'ma_vv', 'dmvv');
  f.add_onResponseComplete(on$FormJob$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged&Identification;);
  f._tabContainer._loaded = true;
}
function close$FormJob(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged&Identification;);} catch (ex) {}
  try {f.remove_onResponseComplete(on$FormJob$ResponseComplete)} catch (ex) {}
  objectBehavior$Dir$Code.dispose(f);
}
/* <flatten type="Javascript"> */
function on$FormJob$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Suggestion':
      objectBehavior$Dir$Code.suggestion(f, result[0].Value);
      break;
    case 'Checking':
      objectBehavior$Dir$Code.checkCode(f);
      break;
    default:
      break;
  }
}
